def can_partition(arr: list[int]) -> int:
    total = sum(arr)
    if total % 2 != 0:
        return 0
    target = total // 2
    dp = [False] * (target + 1)
    dp[0] = True
    for num in arr:
        for j in range(target, num - 1, -1):
            dp[j] = dp[j] or dp[j - num]
    return 1 if dp[target] else 0

pub fn can_partition(arr: &[i32]) -> i32 {
    let total: i32 = arr.iter().sum();
    if total % 2 != 0 { return 0; }
    let target = (total / 2) as usize;
    let mut dp = vec![false; target + 1];
    dp[0] = true;
    for &num in arr {
        let num = num as usize;
        for j in (num..=target).rev() {
            dp[j] = dp[j] || dp[j - num];
        }
    }
    if dp[target] { 1 } else { 0 }
}

object CanPartition {

  def canPartition(arr: Array[Int]): Int = {
    val total = arr.sum
    if (total % 2 != 0) return 0
    val target = total / 2
    val dp = Array.fill(target + 1)(false)
    dp(0) = true
    for (num <- arr) {
      for (j <- target to num by -1) {
        dp(j) = dp(j) || dp(j - num)
      }
    }
    if (dp(target)) 1 else 0
  }
}

func canPartition(_ arr: [Int]) -> Int {
    let total = arr.reduce(0, +)
    if total % 2 != 0 { return 0 }
    let target = total / 2
    var dp = [Bool](repeating: false, count: target + 1)
    dp[0] = true
    for num in arr {
        for j in stride(from: target, through: num, by: -1) {
            dp[j] = dp[j] || dp[j - num]
        }
    }
    return dp[target] ? 1 : 0
}

export function canPartition(arr: number[]): number {
    const total = arr.reduce((a, b) => a + b, 0);
    if (total % 2 !== 0) return 0;
    const target = total / 2;
    const dp = new Array(target + 1).fill(false);
    dp[0] = true;
    for (const num of arr) {
        for (let j = target; j >= num; j--) {
            dp[j] = dp[j] || dp[j - num];
        }
    }
    return dp[target] ? 1 : 0;
}
